{
  "server": {
    "name": "appscreen-listing-mcp",
    "version": "1.1.0"
  },
  "scope": {
    "deterministicOnly": true,
    "includesAiGeneration": false
  },
  "output": {
    "presetDevices": {
      "iphone-6.9": {
        "width": 1320,
        "height": 2868
      },
      "iphone-6.7": {
        "width": 1290,
        "height": 2796
      },
      "iphone-6.5": {
        "width": 1284,
        "height": 2778
      },
      "iphone-5.5": {
        "width": 1242,
        "height": 2208
      },
      "ipad-12.9": {
        "width": 2048,
        "height": 2732
      },
      "ipad-11": {
        "width": 1668,
        "height": 2388
      },
      "android-phone": {
        "width": 1080,
        "height": 1920
      },
      "android-phone-hd": {
        "width": 1440,
        "height": 2560
      },
      "android-tablet-7": {
        "width": 1200,
        "height": 1920
      },
      "android-tablet-10": {
        "width": 1600,
        "height": 2560
      }
    },
    "customDeviceSupported": true,
    "outputModes": [
      "mcp-output",
      "app-dir"
    ],
    "outputPathTemplate": "<outputDir>/<device>/<language>/screenshot-<index>.png"
  },
  "listingSpecContract": {
    "required": [
      "projectName",
      "outputDevices[]",
      "languages[]",
      "screens[]"
    ],
    "screenFields": [
      "id",
      "images",
      "text? (headline/subheadline maps)",
      "style? (background/screenshot/text)"
    ],
    "optional": [
      "defaults",
      "allowPartial",
      "outputMode",
      "outputDir",
      "assetsBaseDir",
      "customSize"
    ],
    "supportedStyles": {
      "screenshot": [
        "scale",
        "x",
        "y",
        "rotation",
        "perspective",
        "cornerRadius",
        "use3D",
        "device3D (iphone/android)",
        "rotation3D",
        "shadow"
      ],
      "text": [
        "headlineFont",
        "headlineSize",
        "headlineColor",
        "position (top/bottom)",
        "offsetX",
        "offsetY",
        "textRotation",
        "lineHeight",
        "textShadow",
        "textOutline"
      ]
    }
  },
  "automationSurface": {
    "namespace": "window.__appscreenAutomation",
    "methods": [
      "getVersion",
      "healthCheck",
      "getScreenshotCount",
      "resetProject",
      "importLocalizedScreenshots",
      "applyListingSpec",
      "applyProjectJson",
      "renderAllPng",
      "renderPngAt"
    ]
  },
  "reliability": {
    "timeoutMs": 120000,
    "bootstrapWaitMs": 120000,
    "comboRetries": 1,
    "sessionRecycleAfterCombos": 4,
    "sessionRecycleIsHardLimit": false
  },
  "tools": [
    "get_capabilities",
    "list_output_presets",
    "validate_listing_spec",
    "dry_run_listing_job",
    "generate_listing_images",
    "render_project_json",
    "diagnose_app_boot"
  ],
  "exampleSpec": {
    "projectName": "Example Listing Job",
    "outputDevices": [
      "iphone-6.9",
      "android-phone"
    ],
    "languages": [
      "en",
      "de"
    ],
    "screens": [
      {
        "id": "screen-1",
        "images": {
          "en": "fixtures/screen1-en.png",
          "de": "fixtures/screen1-de.png",
          "default": "fixtures/screen1-en.png"
        },
        "text": {
          "headline": {
            "en": "Track Everything",
            "de": "Alles im Blick"
          },
          "subheadline": {
            "en": "Fast and simple",
            "de": "Schnell und einfach"
          }
        }
      }
    ],
    "outputMode": "app-dir",
    "outputDir": "img/generated-listings",
    "allowPartial": false
  }
}
